CREATE TABLE import_batches (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), created_by_user_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, source_filename text NOT NULL, file_hash text NOT NULL, status text NOT NULL DEFAULT 'staging', summary jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), completed_at timestamptz);
CREATE INDEX import_batches_status_index ON import_batches(status); CREATE INDEX import_batches_hash_index ON import_batches(file_hash);
CREATE TABLE import_files (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), batch_id uuid NOT NULL UNIQUE REFERENCES import_batches(id) ON DELETE CASCADE, original_filename text NOT NULL, mime_type text NOT NULL, byte_size integer NOT NULL, sha256 text NOT NULL, contents bytea NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE import_sheets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), batch_id uuid NOT NULL REFERENCES import_batches(id) ON DELETE CASCADE, sheet_name text NOT NULL, sheet_order integer NOT NULL, row_count integer NOT NULL, column_count integer NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(batch_id, sheet_name));
CREATE TABLE import_rows (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), sheet_id uuid NOT NULL REFERENCES import_sheets(id) ON DELETE CASCADE, source_row_number integer NOT NULL, raw_values jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(sheet_id, source_row_number));
CREATE TABLE import_cells (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), row_id uuid NOT NULL REFERENCES import_rows(id) ON DELETE CASCADE, column_number integer NOT NULL, column_label text NOT NULL, raw_value jsonb, display_value text, formula text, UNIQUE(row_id, column_number));
CREATE TABLE import_mappings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), batch_id uuid NOT NULL REFERENCES import_batches(id) ON DELETE CASCADE, sheet_name text NOT NULL, source_column text NOT NULL, destination_field text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE import_proposals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), batch_id uuid NOT NULL REFERENCES import_batches(id) ON DELETE CASCADE, source_row_id uuid NOT NULL REFERENCES import_rows(id) ON DELETE CASCADE, entity_type text NOT NULL, proposed_action text NOT NULL, status text NOT NULL DEFAULT 'pending', payload jsonb NOT NULL, duplicate_key text, created_at timestamptz NOT NULL DEFAULT now(), decided_at timestamptz);
CREATE INDEX import_proposals_batch_status_index ON import_proposals(batch_id, status); CREATE INDEX import_proposals_duplicate_index ON import_proposals(duplicate_key);
CREATE TABLE import_field_changes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), proposal_id uuid NOT NULL REFERENCES import_proposals(id) ON DELETE CASCADE, field_name text NOT NULL, incoming_value jsonb, existing_value jsonb, change_type text NOT NULL);
CREATE TABLE import_reviews (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), proposal_id uuid NOT NULL REFERENCES import_proposals(id) ON DELETE CASCADE, reviewer_user_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, decision text NOT NULL, note text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE import_errors (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), batch_id uuid NOT NULL REFERENCES import_batches(id) ON DELETE CASCADE, sheet_name text, source_row_number integer, code text NOT NULL, message text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
